import{c as a,Q as e,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Cat Wu 面試了幾百個 PM 候選人，幾乎沒人答對一個問題：AI 產品經理到底應該干什麼？","description":"","frontmatter":{"title":"Cat Wu 面試了幾百個 PM 候選人，幾乎沒人答對一個問題：AI 產品經理到底應該干什麼？","date":"2026-04-24T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-24-cat-wu-ai-pm-anthropic.md","filePath":"research/ai-articles/scored/2026-04-24-cat-wu-ai-pm-anthropic.md","lastUpdated":1779894392000}'),l={name:"research/ai-articles/scored/2026-04-24-cat-wu-ai-pm-anthropic.md"};function d(i,t,n,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="cat-wu-面試了幾百個-pm-候選人-幾乎沒人答對一個問題-ai-產品經理到底應該干什麼" tabindex="-1">Cat Wu 面試了幾百個 PM 候選人，幾乎沒人答對一個問題：AI 產品經理到底應該干什麼？ <a class="header-anchor" href="#cat-wu-面試了幾百個-pm-候選人-幾乎沒人答對一個問題-ai-產品經理到底應該干什麼" aria-label="Permalink to &quot;Cat Wu 面試了幾百個 PM 候選人，幾乎沒人答對一個問題：AI 產品經理到底應該干什麼？&quot;">​</a></h1><p><strong>來源（X Article）</strong>：<a href="https://x.com/dotey/status/2047537778959778209" target="_blank" rel="noreferrer">https://x.com/dotey/status/2047537778959778209</a><br><strong>作者</strong>：宝玉 (@dotey)，提示工程師<br><strong>發佈日期</strong>：2026-04-24<br><strong>收錄日期</strong>：2026-04-27<br><strong>原始 Podcast</strong>：<a href="https://www.lennysnewsletter.com/p/how-anthropics-product-team-moves" target="_blank" rel="noreferrer">How Anthropic&#39;s product team moves faster than anyone else | Cat Wu</a>（Lenny&#39;s Newsletter，2026-04-23）<br><strong>延伸閱讀</strong>：<a href="https://claude.com/blog/product-management-on-the-ai-exponential" target="_blank" rel="noreferrer">Product management on the AI exponential</a>（Cat Wu，claude.com，2026-03-19）</p><hr><h2 id="文章背景" tabindex="-1">文章背景 <a class="header-anchor" href="#文章背景" aria-label="Permalink to &quot;文章背景&quot;">​</a></h2><p>Cat Wu 是 Anthropic Claude Code 和 Cowork 的產品負責人，與工程負責人 Boris Cherny 搭檔，帶領團隊把產品功能交付週期從半年壓縮到一天。本文整理自 Lenny&#39;s Podcast 最新一期訪談，涵蓋 Anthropic 內部速度文化、PM 角色的劇變、源代碼洩漏善後，以及 OpenClaw 封堵決策等話題。</p><hr><h2 id="核心觀點-20-個段落摘要" tabindex="-1">核心觀點（20 個段落摘要） <a class="header-anchor" href="#核心觀點-20-個段落摘要" aria-label="Permalink to &quot;核心觀點（20 個段落摘要）&quot;">​</a></h2><h3 id="_1-與-boris-cherny-的搭檔模式" tabindex="-1">1. 與 Boris Cherny 的搭檔模式 <a class="header-anchor" href="#_1-與-boris-cherny-的搭檔模式" aria-label="Permalink to &quot;1. 與 Boris Cherny 的搭檔模式&quot;">​</a></h3><p>與工程負責人 Boris Cherny 維持「80% 心智同步、20% 各自專注」的工作方式——大多數決策兩人方向一致，不需要反覆對齊。</p><h3 id="_2-pm-面試最常見的錯誤" tabindex="-1">2. PM 面試最常見的錯誤 <a class="header-anchor" href="#_2-pm-面試最常見的錯誤" aria-label="Permalink to &quot;2. PM 面試最常見的錯誤&quot;">​</a></h3><p>面試幾百個 PM 候選人，幾乎沒人答對的問題：<strong>AI 產品經理到底應該干什麼？</strong><br> 大多數候選人仍停留在「6-12 個月 roadmap」的舊思維，未能理解 AI 時代節奏根本不同。</p><blockquote><p>最優秀的 AI PM，是那些能夠想清楚：「從有這個想法，到把產品交到用戶手中，我怎麼縮短這段時間？」的人。</p></blockquote><h3 id="_3-快速交付的三個機制" tabindex="-1">3. 快速交付的三個機制 <a class="header-anchor" href="#_3-快速交付的三個機制" aria-label="Permalink to &quot;3. 快速交付的三個機制&quot;">​</a></h3><ul><li><strong>目標清晰</strong>：方向明確讓團隊不需反覆對齊</li><li><strong>Research Preview 機制</strong>：降低發布門檻——以「研究預覽」名義早期發布，獲取真實反饋</li><li><strong>長青啟動室（Evergreen Launch Room）</strong>：跨職能協調室，常設化而非一次性 sprint</li></ul><h3 id="_4-prd-已死-週期複盤取而代之" tabindex="-1">4. PRD 已死，週期複盤取而代之 <a class="header-anchor" href="#_4-prd-已死-週期複盤取而代之" aria-label="Permalink to &quot;4. PRD 已死，週期複盤取而代之&quot;">​</a></h3><p>傳統 PRD 被替換為：</p><ul><li><strong>每週 metrics readout</strong>（關注真實數據而非計劃書）</li><li><strong>團隊原則文件（Team Principles Doc）</strong>：讓每個人在沒有 PM 盯著的情況下仍能做出對齊的決策</li></ul><h3 id="_5-速度文化早於-mythos-模型" tabindex="-1">5. 速度文化早於 Mythos 模型 <a class="header-anchor" href="#_5-速度文化早於-mythos-模型" aria-label="Permalink to &quot;5. 速度文化早於 Mythos 模型&quot;">​</a></h3><p>交付速度的提升<strong>早於</strong>強力 AI 模型的出現——根本驅動力是文化與流程，而非工具。</p><h3 id="_6-源代碼洩漏的處置" tabindex="-1">6. 源代碼洩漏的處置 <a class="header-anchor" href="#_6-源代碼洩漏的處置" aria-label="Permalink to &quot;6. 源代碼洩漏的處置&quot;">​</a></h3><p>源代碼洩漏被定性為<strong>流程失敗</strong>而非個人失誤——相關人員被留任，防範措施強化。強調「不怪人，修系統」的文化。</p><h3 id="_7-封堵-openclaw-訂閱的原因" tabindex="-1">7. 封堵 OpenClaw 訂閱的原因 <a class="header-anchor" href="#_7-封堵-openclaw-訂閱的原因" aria-label="Permalink to &quot;7. 封堵 OpenClaw 訂閱的原因&quot;">​</a></h3><p>以「容量管理」為由封堵第三方工具 OpenClaw——原因是第三方工具對系統造成不成比例的負擔，屬於資源保護措施而非競爭封鎖。</p><h3 id="_8-pm-團隊結構" tabindex="-1">8. PM 團隊結構 <a class="header-anchor" href="#_8-pm-團隊結構" aria-label="Permalink to &quot;8. PM 團隊結構&quot;">​</a></h3><p>30-40 名 PM，分佈於五個部門：</p><ul><li>研究（Research）</li><li>開發者平台（Developer Platform）</li><li>Claude Code</li><li>企業（Enterprise）</li><li>成長（Growth）</li></ul><p>大多數 PM 來自工程師或工程師轉型背景。</p><blockquote><p>Product taste 是極稀缺的技能，我們幾乎會錄取任何能展現這個能力的人。</p></blockquote><h3 id="_9-角色邊界的消融" tabindex="-1">9. 角色邊界的消融 <a class="header-anchor" href="#_9-角色邊界的消融" aria-label="Permalink to &quot;9. 角色邊界的消融&quot;">​</a></h3><ul><li>工程師在寫程式的同時也在做產品決策</li><li>設計師在寫程式</li><li>PM、工程、設計的邊界正在消融</li></ul><h3 id="_10-agi-校準感——最難培養的-pm-技能" tabindex="-1">10. AGI 校準感——最難培養的 PM 技能 <a class="header-anchor" href="#_10-agi-校準感——最難培養的-pm-技能" aria-label="Permalink to &quot;10. AGI 校準感——最難培養的 PM 技能&quot;">​</a></h3><p>最難的技能：在<strong>當前模型能力限制</strong>內判斷產品方向——既不過度悲觀（認為模型做不到），也不過度樂觀（忽略當前限制）。</p><p>這被稱為「剛好適量的 AGI 信念」（right amount of AGI belief）。</p><h3 id="_11-人類仍然不可被替代的領域" tabindex="-1">11. 人類仍然不可被替代的領域 <a class="header-anchor" href="#_11-人類仍然不可被替代的領域" aria-label="Permalink to &quot;11. 人類仍然不可被替代的領域&quot;">​</a></h3><ul><li>常識判斷</li><li>人際關係理解</li></ul><p>這兩個領域仍然是人類的護城河。</p><h3 id="_12-高壓環境的日常管理" tabindex="-1">12. 高壓環境的日常管理 <a class="header-anchor" href="#_12-高壓環境的日常管理" aria-label="Permalink to &quot;12. 高壓環境的日常管理&quot;">​</a></h3><p>面對 P0000 級別問題的連環爆發，靠以下三點維持：</p><ul><li>睡眠（不省略）</li><li>優先排序（不什麼都做）</li><li>接受不完美（接受有些事做不好）</li></ul><h3 id="_13-速度的代價" tabindex="-1">13. 速度的代價 <a class="header-anchor" href="#_13-速度的代價" aria-label="Permalink to &quot;13. 速度的代價&quot;">​</a></h3><p>高速交付的副作用：</p><ul><li>功能同時上線導致<strong>重疊與用戶混淆</strong></li><li><strong>一致性被犧牲</strong>換取速度</li></ul><h3 id="_14-統一使命降低組織摩擦" tabindex="-1">14. 統一使命降低組織摩擦 <a class="header-anchor" href="#_14-統一使命降低組織摩擦" aria-label="Permalink to &quot;14. 統一使命降低組織摩擦&quot;">​</a></h3><p>Anthropic 的統一使命讓各團隊能夠放棄個人 KR，優先服務公司整體目標，消除大多數組織政治的根源。</p><h3 id="_15-產品組合使用模式" tabindex="-1">15. 產品組合使用模式 <a class="header-anchor" href="#_15-產品組合使用模式" aria-label="Permalink to &quot;15. 產品組合使用模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>產品</th><th>主要用途</th></tr></thead><tbody><tr><td>CLI</td><td>開發者，深度整合</td></tr><tr><td>Desktop</td><td>主力日常開發</td></tr><tr><td>Web/Mobile</td><td>輕量存取</td></tr><tr><td>Cowork</td><td>知識工作（Todo、Slides）</td></tr></tbody></table><h3 id="_16-客製化應用程式" tabindex="-1">16. 客製化應用程式 <a class="header-anchor" href="#_16-客製化應用程式" aria-label="Permalink to &quot;16. 客製化應用程式&quot;">​</a></h3><p>Anthropic 內部大量使用客製化 AI 工具——「每個人都有自己的個人化 Claude」。</p><h3 id="_17-token-經濟學" tabindex="-1">17. Token 經濟學 <a class="header-anchor" href="#_17-token-經濟學" aria-label="Permalink to &quot;17. Token 經濟學&quot;">​</a></h3><p>Token 成本持續上升，但仍低於工程師薪資成本——ROI 仍然正向。</p><h3 id="_18-claude-的個性差異化" tabindex="-1">18. Claude 的個性差異化 <a class="header-anchor" href="#_18-claude-的個性差異化" aria-label="Permalink to &quot;18. Claude 的個性差異化&quot;">​</a></h3><p>Claude 的<strong>低自我（low ego）和正向能量</strong>是核心差異化因素，超越純粹能力指標。</p><h3 id="_19-產品願景路線圖" tabindex="-1">19. 產品願景路線圖 <a class="header-anchor" href="#_19-產品願景路線圖" aria-label="Permalink to &quot;19. 產品願景路線圖&quot;">​</a></h3><p>演進路徑：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>單一任務 → 多任務 → Agent 矩陣（多 Agent 協同）</span></span></code></pre></div><h3 id="_20-個人興趣" tabindex="-1">20. 個人興趣 <a class="header-anchor" href="#_20-個人興趣" aria-label="Permalink to &quot;20. 個人興趣&quot;">​</a></h3><p>閱讀推薦、Waymo、攀岩，以及「退休計畫」（玩笑性質）。</p><hr><h2 id="cat-wu-自述-ai-時代-pm-的四個工作法轉變" tabindex="-1">Cat Wu 自述：AI 時代 PM 的四個工作法轉變 <a class="header-anchor" href="#cat-wu-自述-ai-時代-pm-的四個工作法轉變" aria-label="Permalink to &quot;Cat Wu 自述：AI 時代 PM 的四個工作法轉變&quot;">​</a></h2><p>（來源：claude.com 博文，2026-03-19）</p><table tabindex="0"><thead><tr><th>舊工作法</th><th>新工作法</th><th>說明</th></tr></thead><tbody><tr><td>長期 Roadmap</td><td><strong>Side Quest 文化</strong></td><td>自主實驗，午後原型就是功能起點</td></tr><tr><td>PRD 文件</td><td><strong>Demo 取代 PRD</strong></td><td>讓 Claude Code 做出 prototype，原型錨定決策</td></tr><tr><td>固定功能設計</td><td><strong>模型更新時重訪功能</strong></td><td>每個新模型版本都是重新設計的機會</td></tr><tr><td>防禦性複雜設計</td><td><strong>擁抱簡單</strong></td><td>Workaround 會隨模型進步消失，越簡單的設計越持久</td></tr></tbody></table><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>7/10</td><td>Demo 取代 PRD、research preview 機制、週期 metrics readout 可直接套用於 cc-workspace 的任務規劃流程；side quest 文化呼應 karpathy-principles</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>AGI 校準感作為核心 PM 技能、Evergreen Launch Room 機制、「模型更新時重訪功能」設計原則——均為現有 Skills 未涵蓋的洞見</td></tr><tr><td>C. 證據品質</td><td>8/10</td><td>直接訪談 Anthropic 現任 Claude Code 產品負責人，一手陳述；並有 claude.com 官方博文佐證</td></tr><tr><td>D. 技術深度</td><td>7/10</td><td>有具體流程（metrics readout 取代 PRD、Research Preview 機制）但缺乏實作細節（例如 Principles Doc 的具體格式）</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>適用於所有 AI-native 產品團隊，不限 Anthropic 情境；「重訪功能 with 新模型」對任何使用 Claude 的開發者均成立</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.6/10</strong></td><td>7×0.3 + 8×0.2 + 8×0.2 + 7×0.15 + 8×0.15 = 2.1 + 1.6 + 1.6 + 1.05 + 1.2 = <strong>7.55 ≈ 7.6</strong></td></tr></tbody></table><p><strong>整合決策</strong>：Rule（更新既有規則）<br><strong>整合位置</strong>：<code>.claude/rules/karpathy-principles.md</code> — 補充「模型更新時重訪功能」和「Demo 取代 PRD」作為 Simplicity First + Surgical Changes 的具體 AI 時代變體<br><strong>整合狀態</strong>：待實作</p>',65)])])}const b=a(l,[["render",d]]);export{u as __pageData,b as default};
